module TopModule (
    input wire [7:0] I0, I1, I2, I3, I4, I5, I6, I7,  // 8 input lines
    input wire [2:0] S0, S1, S2,                    // 3 selection lines
    output wire Y                                    // output line
);
    wire [7:0] I;  // Intermediate wire to hold the inputs

    // Assigning the input wires to the intermediate wire array
    assign {I[7], I[6], I[5], I[4], I[3], I[2], I[1], I[0]} = {I7, I6, I5, I4, I3, I2, I1, I0};

    // Instantiating the 8-to-1 MUX module
    mux8to1 uut (
        .I(I),
        .S({S2, S1, S0}),
        .Y(Y)
    );
endmodule
